  const handleToggleOficioNumber = async (num: number) => {
    if (!user) return;
    let updated;
    if (usedOficioNumbers.includes(num)) {
      updated = usedOficioNumbers.filter(n => n !== num);
    } else {
      updated = [...usedOficioNumbers, num].sort((a, b) => a - b);
    }
    const oficioRef = doc(db, "correspondence", user.uid);
    await setDoc(oficioRef, { usedNumbers: updated }, { merge: true });
  };

