                }} className="mt-6 w-full p-5 border-2 border-dashed border-slate-200 rounded-2xl text-[10px] font-black uppercase text-slate-400 hover:bg-slate-50">Adicionar Empresa</button>
             </div>
          </div>
        )}

        <Modal isOpen={isModalOpen} onClose={() => { setIsModalOpen(false); resetDeadlineForm(); }} title={editingDeadlineId ? "Editar Prazo" : "Novo Registro"}>
          <form onSubmit={handleAddDeadline} className="grid grid-cols-2 gap-8">
            <div className="space-y-3"><label className="text-[10px] font-black text-slate-400 uppercase">Tipo</label><select className="w-full bg-slate-50 p-6 rounded-2xl font-bold" value={newDeadline.peca} onChange={e => setNewDeadline(p => ({ ...p, peca: e.target.value }))} required><option value="">Selecione...</option>{dynamicSettings.pecas.map(p => <option key={p} value={p}>{p}</option>)}</select></div>
            <div className="space-y-3"><label className="text-[10px] font-black text-slate-400 uppercase">Empresa</label><select className="w-full bg-slate-50 p-6 rounded-2xl font-bold" value={newDeadline.empresa} onChange={e => setNewDeadline(p => ({ ...p, empresa: e.target.value }))} required><option value="">Selecione...</option>{dynamicSettings.empresas.map(e => <option key={e} value={e}>{e}</option>)}</select></div>
            <div className="space-y-3"><label className="text-[10px] font-black text-slate-400 uppercase">Data Limite</label><input type="date" className="w-full bg-slate-50 p-6 rounded-2xl font-bold" value={newDeadline.data} onChange={e => setNewDeadline(p => ({ ...p, data: e.target.value }))} required /></div>
            <div className="space-y-3"><label className="text-[10px] font-black text-slate-400 uppercase">Responsável</label><select className="w-full bg-slate-50 p-6 rounded-2xl font-bold" value={newDeadline.responsavel} onChange={e => setNewDeadline(p => ({ ...p, responsavel: e.target.value }))} required><option value="">Selecione...</option>{dynamicSettings.responsaveis.map(r => <option key={r} value={r}>{r}</option>)}</select></div>
            <div className="col-span-2 space-y-3"><label className="text-[10px] font-black text-slate-400 uppercase">Google Drive Link</label><input type="url" className="w-full bg-slate-50 p-6 rounded-2xl font-bold" value={newDeadline.documentUrl || ''} onChange={e => setNewDeadline(p => ({ ...p, documentUrl: e.target.value }))} placeholder="https://drive.google.com/..." /></div>
            <div className="col-span-2 space-y-4">
              <div className="flex justify-between items-center"><label className="text-[10px] font-black text-slate-400 uppercase">Objeto / Assunto</label><button type="button" disabled={isSuggesting || !newDeadline.peca || !newDeadline.empresa} onClick={async () => { setIsSuggesting(true); const suggestion = await suggestActionObject(newDeadline.peca!, newDeadline.empresa!); setNewDeadline(prev => ({ ...prev, assunto: suggestion })); setIsSuggesting(false); }} className="text-[9px] font-black uppercase flex items-center gap-2 px-4 py-2 rounded-full bg-blue-50 text-blue-600 hover:bg-blue-600 hover:text-white transition-all">IA Sugerir</button></div>
              <textarea className="w-full bg-slate-50 p-8 rounded-3xl font-medium min-h-[120px]" placeholder="Descrição..." value={newDeadline.assunto} onChange={e => setNewDeadline(p => ({ ...p, assunto: e.target.value }))} required />
            </div>
            <button type="submit" className="col-span-2 bg-slate-950 text-white p-7 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-blue-600 transition-all">{editingDeadlineId ? 'Salvar' : 'Registrar'}</button>
          </form>
        </Modal>
      </main>
    </div>
  );
}

