            <div className="col-span-2 space-y-3"><label className="text-[10px] font-black text-slate-400 uppercase ml-4">Link do Documento (Drive)</label><input type="url" className="w-full bg-slate-50 p-6 rounded-2xl font-bold" value={newDeadline.documentUrl || ''} onChange={e => setNewDeadline(p => ({ ...p, documentUrl: e.target.value }))} placeholder="https://drive.google.com/..." /></div>
            <div className="col-span-2 space-y-4">
              <div className="flex justify-between items-center px-4"><label className="text-[10px] font-black text-slate-400 uppercase">Objeto da Ação</label><button type="button" disabled={isSuggesting || !newDeadline.peca || !newDeadline.empresa} onClick={async () => { setIsSuggesting(true); const suggestion = await suggestActionObject(newDeadline.peca!, newDeadline.empresa!); setNewDeadline(prev => ({ ...prev, assunto: suggestion })); setIsSuggesting(false); }} className="text-[9px] font-black uppercase flex items-center gap-2 px-4 py-2 rounded-full bg-blue-50 text-blue-600 hover:bg-blue-600 hover:text-white transition-all shadow-sm">IA SUGERIR</button></div>
              <textarea className="w-full bg-slate-50 p-8 rounded-3xl font-medium min-h-[120px]" placeholder="Descreva os detalhes do prazo..." value={newDeadline.assunto} onChange={e => setNewDeadline(p => ({ ...p, assunto: e.target.value }))} required />
