            </div>
            <div className="space-y-3">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-4 tracking-widest">Órgão Julgador</label>
              <input type="text" className="w-full bg-slate-50 p-6 rounded-2xl font-bold focus:ring-2 focus:ring-blue-100 outline-none" placeholder="Ex: STF, STJ, TJSP..." value={newJuris.orgao} onChange={e => setNewJuris(p => ({ ...p, orgao: e.target.value }))} required />
            </div>
            <div className="col-span-2 space-y-3">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-4 tracking-widest">Tema / Tópico Central</label>
              <input type="text" className="w-full bg-slate-50 p-6 rounded-2xl font-bold focus:ring-2 focus:ring-blue-100 outline-none" placeholder="Ex: Exclusão do ICMS da base de cálculo do PIS/COFINS" value={newJuris.tema} onChange={e => setNewJuris(p => ({ ...p, tema: e.target.value }))} required />
            </div>
            <div className="col-span-2 space-y-3">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-4 tracking-widest">Enunciado / Ementa Completa</label>
              <textarea className="w-full bg-slate-50 p-8 rounded-3xl font-medium min-h-[250px] focus:ring-2 focus:ring-blue-100 outline-none" placeholder="Cole aqui o texto da ementa ou acórdão..." value={newJuris.enunciado} onChange={e => setNewJuris(p => ({ ...p, enunciado: e.target.value }))} required />
            </div>
            <button type="submit" className="col-span-2 bg-slate-900 text-white p-7 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-blue-600 transition-all shadow-xl active:scale-95">
              {editingJurisId ? 'ATUALIZAR PRECEDENTE' : 'SALVAR JURISPRUDÊNCIA'}
            </button>
          </form>
        </Modal>
      </main>
    </div>
  );
}

