// Helpers
const formatLocalDate = (d: string) => {
  if (!d) return '-';
  const [year, month, day] = d.split('-').map(Number);
  return new Date(year, month - 1, day).toLocaleDateString('pt-BR');
};

const getDaysDiff = (d: string) => {
  if (!d) return 999;
  const today = new Date(); today.setHours(0,0,0,0);
  const [y, m, day] = d.split('-').map(Number);
  const target = new Date(y, m - 1, day);
  return Math.ceil((target.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
};

const Modal = ({ isOpen, onClose, title, children }: any) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-slate-900/40 backdrop-blur-md animate-fade-in">
      <div className="bg-white w-full max-w-3xl rounded-[2rem] shadow-2xl flex flex-col relative overflow-hidden">
        <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">{title}</h3>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-lg transition-all"><Icons.Close /></button>
        </div>
        <div className="p-8 overflow-y-auto max-h-[85vh] custom-scrollbar">{children}</div>
      </div>
    </div>
  );
};

export default function App() {
