      setDeadlines(d.sort((a,b) => a.data.localeCompare(b.data)));
    });
  }, [user]);

  useEffect(() => {
    if (!user) return;
    const q = query(collection(db, "jurisprudencias"), where("userId", "==", user.uid));
    return onSnapshot(q, (s) => {
      const d = s.docs.map(doc => ({ id: doc.id, ...doc.data() })) as Jurisprudencia[];
      setJurisprudencias(d.sort((a,b) => b.createdAt.localeCompare(a.createdAt)));
    });
  }, [user]);

  useEffect(() => {
    if (!user) return;
    const docRef = doc(db, "correspondence", user.uid);
    return onSnapshot(docRef, (snap) => {
      if (snap.exists()) {
        const data = snap.data();
        setUsedOficios(data.oficio || []);
        setUsedMemos(data.memorando || []);
      }
    });
  }, [user]);

  useEffect(() => {
    if (!user) return;
    const docRef = doc(db, "settings", user.uid);
    return onSnapshot(docRef, (snap) => {
      if (snap.exists()) {
        const data = snap.data() as NotificationSettings;
        setSettings(prev => ({ ...prev, ...data }));
      }
    });
  }, [user]);

