        <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingId ? "Editar Registro" : "Novo Prazo Processual"}>
          <form onSubmit={handleSaveDeadline} className="grid grid-cols-2 gap-6">
            <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">Peça</label><select className="w-full bg-slate-50 p-4 rounded-xl font-bold text-xs" value={form.peca} onChange={e => setForm({...form, peca: e.target.value})} required><option value="">Selecione...</option>{settings.pecas.map(o => <option key={o} value={o}>{o}</option>)}</select></div>
            <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">Cliente</label><select className="w-full bg-slate-50 p-4 rounded-xl font-bold text-xs" value={form.empresa} onChange={e => setForm({...form, empresa: e.target.value})} required><option value="">Selecione...</option>{settings.empresas.map(o => <option key={o} value={o}>{o}</option>)}</select></div>
            <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">Vencimento</label><input type="date" className="w-full bg-slate-50 p-4 rounded-xl font-bold text-xs" value={form.data} onChange={e => setForm({...form, data: e.target.value})} required /></div>
            <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">Responsável</label><select className="w-full bg-slate-50 p-4 rounded-xl font-bold text-xs" value={form.responsavel} onChange={e => setForm({...form, responsavel: e.target.value})} required><option value="">Selecione...</option>{settings.responsaveis.map(o => <option key={o} value={o}>{o}</option>)}</select></div>
            <div className="col-span-2 space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">URL Processo/Link</label><input type="url" className="w-full bg-slate-50 p-4 rounded-xl font-bold text-xs" value={form.documentUrl || ''} onChange={e => setForm({...form, documentUrl: e.target.value})} placeholder="https://..." /></div>
            <div className="col-span-2 space-y-3">
              <div className="flex justify-between items-center px-2"><label className="text-[10px] font-black text-slate-400 uppercase">Providência Necessária</label><button type="button" disabled={isSuggesting || !form.peca} onClick={async () => { setIsSuggesting(true); const s = await suggestActionObject(form.peca!, form.empresa || 'Empresa'); setForm({...form, assunto: s}); setIsSuggesting(false); }} className="text-[9px] font-black text-blue-600 bg-blue-50 px-4 py-1.5 rounded-lg border border-blue-100 hover:bg-blue-100 transition-all flex items-center gap-2"><Icons.Sparkles /> {isSuggesting ? 'Sugerindo...' : 'Sugerir IA'}</button></div>
              <textarea className="w-full bg-slate-50 p-6 rounded-2xl font-medium text-xs min-h-[100px] resize-none border border-slate-100" value={form.assunto} onChange={e => setForm({...form, assunto: e.target.value})} placeholder="Detalhamento do prazo..." required />
            </div>
            <button className="col-span-2 bg-slate-900 text-white p-5 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-blue-600 shadow-xl transition-all">Salvar Prazo</button>
          </form>
        </Modal>

        <Modal isOpen={isJurisModalOpen} onClose={() => setIsJurisModalOpen(false)} title={editingJurisId ? "Editar Jurisprudência" : "Novo Precedente"}>
          <form onSubmit={handleSaveJuris} className="grid grid-cols-2 gap-6">
            <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">Área</label><select className="w-full bg-slate-50 p-4 rounded-xl font-bold text-xs" value={jurisForm.area} onChange={e => setJurisForm({...jurisForm, area: e.target.value})} required><option value="">Selecione...</option>{settings.areasDireito.map(a => <option key={a} value={a}>{a}</option>)}</select></div>
            <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">Órgão</label><select className="w-full bg-slate-50 p-4 rounded-xl font-bold text-xs" value={jurisForm.orgao} onChange={e => setJurisForm({...jurisForm, orgao: e.target.value})} required><option value="">Selecione...</option>{settings.orgaosJulgadores.map(o => <option key={o} value={o}>{o}</option>)}</select></div>
            <div className="col-span-2 space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">Tema Principal</label><select className="w-full bg-slate-50 p-4 rounded-xl font-bold text-xs" value={jurisForm.tema} onChange={e => setJurisForm({...jurisForm, tema: e.target.value})} required><option value="">Selecione...</option>{settings.temasJuris.map(t => <option key={t} value={t}>{t}</option>)}</select></div>
            <div className="col-span-2 space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">Enunciado / Tese</label><textarea className="w-full bg-slate-50 p-6 rounded-2xl font-medium text-xs min-h-[180px] border border-slate-100" value={jurisForm.enunciado} onChange={e => setJurisForm({...jurisForm, enunciado: e.target.value})} placeholder="Texto completo da tese jurídica..." required /></div>
            <button className="col-span-2 bg-slate-900 text-white p-5 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-blue-600 shadow-xl transition-all">Salvar Jurisprudência</button>
          </form>
        </Modal>
      </main>
    </div>
  );
}
